Function in python are first-class objects&nbsp;(runtime / element / argument / return) 1. Treating a Function Like an Object def test(n): """ return n*2 """ return n * 2 print test(5) # 10 ‘doc‘ is used to generate the help text of an object‘help(test)’ do like this in Python Interactive Consoleprint test.doc # ‘ return n*2 ‘ Function object is an instance of the function class.print type(test) # &lt;type ‘function’&gt; assign it, call it, use it as an argumenttmp = testprint tmp(5) # 10print list(map(tmp, range(5))) # [0, 2, 4, 6, 8] 2.&nbsp;Higher-Order Functions A function that takes a function as argument or returns a function fruits = ['fig', 'apple', 'cherry'] print sorted(fruits, key=len) # [‘fig’, ‘apple’, ‘cherry’] Any one-argument function can be used as the key.print sorted(fruits, key=lambda word: word[::-1]) # [‘apple’, ‘fig’, ‘cherry’] 2.1&nbsp;Modern Replacements for map, filter, and reduce def test(n): return n * 2 print list(map(test, range(5))) # [0, 2, 4, 6, 8]print [test(n) for n in range(5)] # [0, 2, 4, 6, 8] print list(map(test, filter(lambda n: n % 2, range(5)))) # [2, 6]print [test(n) for n in range(5) if n % 2] # [2, 6] print reduce(lambda x,y: x+y, range(100)) # 4950print sum(range(100)) # 4950 3.&nbsp;The Seven Flavors of Callable Objects User-defined functions: def or lambda. Built-in functions: like len or time.strftime. Built-in methods: like dict.get. Methods: functions in class. Classes:&nbsp;a class runs its __new__ method to create an instance, then __init__ to initialize it, and finally the instance is returned to the caller. Class instances:&nbsp;if a class defines a __call__ method, then its instances may be invoked as functions. Generator functions:&nbsp;functions or methods that use the yield keyword. [notes]: To determine whether an object is callable, use the callable() built-in function. 4.&nbsp;User-Defined Callable Types Python objects may also be made to behave like functions class Test: def __init__(self, items): self._items = list(items) def pick(self): return self._items.pop() def __call__(self): return self.pick() t = Test(range(5))print t.pick() # 4print t() # 3print callable(t) # True 5. Keyword-Only Parameters Can only be given as a keyword argument. Python 3 only. def tag(name, *content, cls=None, **attrs): # cls: Keyword-Only """ Generate one or more HTML tags """ if cls is not None: attrs['class'] = cls if attrs: attr_str = ''.join(' %s="%s"' % (attr, value) for attr, value in sorted(attrs.items())) else: attr_str = '' if content: return '
'.join('&lt;%s%s&gt;%s&lt;/%s&gt;' % (name, attr_str, c, name) for c in content) else: return '&lt;%s%s /&gt;' % (name, attr_str) print(tag('br')) # &lt;br /&gt; print(tag('a', 'hello', 'world', href='#')) # &lt;a href="#"&gt;hello&lt;/a&gt;
&lt;a href="#"&gt;world&lt;/a&gt; print(tag('div', 'im div~', cls='f-left')) # &lt;div class="f-left"&gt;im div~&lt;/div&gt; print(tag(**{'name': 'img', 'id': 'my_img'})) # &lt;img id="my_img" /&gt; def f(a, *, b): # b: Keyword-Only return a, bprint(f(1, b=2)) # (1, 2) 6.&nbsp;Function Introspection def test(n): return n * 2 test.name = 'double it!' a function uses the dict attribute to store user attributes assigned to itprint test.dict # {‘name’: ‘double it!’} Attributes of functions that don&rsquo;t exist in plain instances 7.&nbsp;Retrieving Information About Parameters def test(a, b=2, c=3, **x): d = a * b * c return d print test.defaults # (2, 3) defaults for keyword-only argumentsprint(test.kwdefaults) # {‘e’: 3}print test.code # &lt;code object test at 0x…&gt; does’t include any variable arguments prefixed with * or **print test.code.co_varnames # (‘a’, ‘b’, ‘c’, ‘d’)print test.code.co_argcount # 3 &nbsp; def test(a, b=2, c=3, **x): d = a * b * c return d from inspect import signature # python 3tmp = signature(test)print(str(tmp)) # (a, b=2, c=3, **x)for name, param in tmp.parameters.items(): # ‘kind’ can also be: VAR_POSITIONAL / VAR_KEYWORD / KEYWORD_ONLY / POSITIONAL_ONLY print(param.kind) # POSITIONAL_OR_KEYWORD print(name) # a print(param.default) # &lt;class ‘inspect._empty’&gt; bind_tmp = tmp.bind(**{‘a’: 11, ‘b’: 22})for name, value in bind_tmp.arguments.items(): print(name, ‘=’, value) # a = 11 
 b = 22 8.&nbsp;Function Annotations Just annotation, noting else! Python 3 only. def test(a:str, b:'in&gt;0'=1) -&gt; str: return a print(test('qqq', 2)) # qqq print(test.__annotations__) # {'a': &lt;class 'str'&gt;, 'b': 'in&gt;0', 'return': &lt;class 'str'&gt;} from inspect import signature # python 3tmp = signature(test)for name, param in tmp.parameters.items(): print(param.annotation) # &lt;class ‘str’&gt; print(param.name) # a print(param.default) # &lt;class ‘inspect._empty’&gt; &nbsp;9.&nbsp;Packages for Functional Programming 9.1&nbsp;operator from operator import mul print mul(4, 5) # 20 from operator import itemgetter # pick items from sequencestest_data = [(‘b’, 2), (‘a’, 1), (‘c’, 3)]for item in sorted(test_data, key=itemgetter(1)): # lambda i: i[1] print item # (‘a’, 1)func = itemgetter(1, 0) # lambda i: (i[1], i[0])for item in test_data: print func(item) # (2, ‘b’) from operator import attrgetter # read attributes from objectsclass A: tmp = 1class B: a = A()class C: b = B() tmp = 2c = C()func = attrgetter(‘b.a.tmp’, ‘tmp’)print func(c) # (1, 2) from operator import methodcallers = ‘The time has come’my_upper = methodcaller(‘upper’)print my_upper(s) # s.upper()my_replace = methodcaller(‘replace’, ‘ ‘, ‘-‘)print my_replace(s) # s.replace(‘ ‘, ‘-‘) #[‘abs’, ‘add’, ‘and_’, ‘attrgetter’, ‘concat’, ‘contains’, ‘countOf’, ‘delitem’, ‘eq’, ‘floordiv’, ‘ge’, ‘getitem’, ‘gt’, ‘iadd’, ‘iand’,‘iconcat’, ‘ifloordiv’, ‘ilshift’, ‘imod’, ‘imul’, ‘index’, ‘indexOf’,‘inv’, ‘invert’, ‘ior’, ‘ipow’, ‘irshift’, ‘is_’, ‘is_not’, ‘isub’,‘itemgetter’, ‘itruediv’, ‘ixor’, ‘le’, ‘length_hint’, ‘lshift’,‘lt’, ‘methodcaller’, ‘mod’, ‘mul’, ‘ne’, ‘neg’, ‘not_’, ‘or_’, ‘pos’,‘pow’, ‘rshift’, ‘setitem’, ‘sub’, ‘truediv’, ‘truth’, ‘xor’] 9.2&nbsp;functools def test(a, b, c): return a * b * c from functools import partialtmp = partial(test, 1, c=2) # can’t ‘b=2’ because ‘c’print list(map(tmp, range(5))) # [0, 2, 4, 6, 8]print test # &lt;function test at 0x10dca0e60&gt;print tmp.func # &lt;function test at 0x10dca0e60&gt;print tmp.args # (1,)print tmp.keywords # {‘c’: 2} &nbsp;

A decorator is a callable that takes another function as argument (the decorated function). The decorator may perform some processing with the decorated function, and returns it or replaces it with another function or callable object. 1.&nbsp;Variable Scope Rules b = 6 def f1(a): print(a) # 3 print(b) # 6 f1(3) &nbsp; b = 6 def f2(a): print(a) # 3 print(b) # UnboundLocalError: local variable 'b' referenced before assignment b = 9 f2(3) 1. When Python compiles the body of the function, it decides that b is a localvariable because it’s assigned within the function.2. Python does not require you to declare variables, but assumes that a variableassigned in the body of a function is local &nbsp; b = 6 def f3(a): global b # declare print(a) # 3 print(b) # 6 b = 9 f3(3) &nbsp;2. Closures Actually, a closure is a function with an extended scope that encompasses nonglobal variables referenced in the body of the function but not defined there. It does not matter whether the function is anonymous or not; what matters is that it can access nonglobal variables that are defined outside of its body.&nbsp; A closure is a function that retains the bindings of the free variables that exist when the function is defined, so that they can be used later when the function is invoked and the defining scope is no longer available. The only situation in which a function may need to deal with external variables that are nonglobal is when it is nested in another function. def make_averager(): series = [] def averager(new_value): series.append(new_value) total = sum(series) return total / len(series) return averager avg = make_averager()print avg(10) # 10print avg(12) # 11print avg(14) # 12print avg.code.co_varnames # (‘new_value’, ‘total’)print avg.code.co_freevars # (‘series’,)print avg.closure # (&lt;cell at 0x1030d1280: list object at 0x1030a97e8&gt;,)print avg.closure[0].cell_contents # [10, 12, 14] free variable: a variable that is not bound in the local scope. 3.&nbsp;The nonlocal Declaration def make_averager(): count = 0 total = 0 def averager(new_value): count += 1 total += new_value return total / count return averager avg = make_averager()print avg(10) # UnboundLocalError: local variable ‘count’ referenced before assignment 1. We actually assign count in the body of averager, and that makes it a local variable.2. We didn’t have this problem before, because we never assigned to the series name,we only called series.append and invoked sum and len on it.3. With immutable types, if you try to rebind them, then you are implicitly creating alocal variable, it’s no longer a free variable, therefore it is not saved in the closure. &nbsp; def make_averager(): count = 0 total = 0 def averager(new_value): nonlocal count, total # ********** count += 1 total += new_value return total / count return averager avg = make_averager()print(avg(10)) # 10.0 1. The nonlocal declaration was introduced in Python 3. It lets you flag a variable as afree variable even when it is assigned a new value within the function. &nbsp;4.&nbsp;Implementing a Simple Decorator Typical behavior of a decorator: It replaces the decorated function with a new function that accepts the same arguments and (usually) returns whatever the decorated function was supposed to return, while also doing some extra processing. def deco(func): print('running deco()') print('func -&gt; %s' % str(func)) def inner(): print('running inner()') return inner @deco # target = deco(target)def target(): print(‘running target()’) target() running deco() # executed immediately when the module is loadedfunc -&gt; &lt;function target at 0x106c460c8&gt;running inner()print(target.name) # inner (function is replaced) &nbsp; import time FMT = '[{elapsed:0.8f}s] {name}({arg_str}) -&gt; {result}' def clock(func): def clocked(*args, **kwargs): t0 = time.time() result = func(*args, **kwargs) elapsed = time.time() - t0 # 用时 name = func.__name__ arg_lst = [] if args: arg_lst.append(', '.join(repr(arg) for arg in args)) if kwargs: pairs = ['%s=%r' % (k, w) for k, w in sorted(kwargs.items())] arg_lst.append(', '.join(pairs)) arg_str = ', '.join(arg_lst) print(FMT.format(**locals())) # any local variable of clocked return result return clocked @clockdef snooze(seconds): time.sleep(seconds) @clockdef factorial(n): return 1 if n &lt; 2 else n*factorial(n-1) print(‘‘ * 40, ‘Calling snooze(.123)’)snooze(.123)print(‘‘ * 40, ‘Calling factorial(6)’)print(‘6! =’, factorial(6)) (‘****************************************’, ‘Calling snooze(.123)’)[0.12694907s] snooze(0.123) -&gt; None(‘****************************************’, ‘Calling factorial(6)’)[0.00000286s] factorial(1) -&gt; 1[0.00004411s] factorial(2) -&gt; 2[0.00005984s] factorial(3) -&gt; 6[0.00007296s] factorial(4) -&gt; 24[0.00014281s] factorial(5) -&gt; 120[0.00015783s] factorial(6) -&gt; 720(‘6! =’, 720) &nbsp;5.&nbsp;Decorators in the Standard Library 5.1&nbsp;functools.wraps import functools def deco(func): @functools.wraps(func) # copy the relevant attributes from func to inner def inner(): print('running inner()') return inner @decodef target(): “””i’m target””” print(‘running target()’) target() # running inner()print(target.name) # targetprint(target.doc) # i’m target &nbsp;5.2&nbsp;functools.lru_cache An optimization technique that works by saving the results of previous invocations of an expensive function, avoiding repeat computations on previously used arguments. The cache is limited by discarding the entries that have not been read for a while. import functools @functools.lru_cache() # Python 3 @clock def fibonacci(n): if n &lt; 2: return n return fibonacci(n-2) + fibonacci(n-1) print(fibonacci(6)) [0.00000095s] fibonacci(0) -&gt; 0[0.00000215s] fibonacci(1) -&gt; 1[0.00036097s] fibonacci(2) -&gt; 1[0.00000167s] fibonacci(3) -&gt; 2[0.00039101s] fibonacci(4) -&gt; 3[0.00000095s] fibonacci(5) -&gt; 5[0.00041699s] fibonacci(6) -&gt; 88@functools.lru_cache(maxsize=128, typed=False)maxsize: how many call results are stored. (should be a power of 2)typed: True -&gt; store results of different argument types separately (1 / 1.0)False -&gt; don’t store[notes]: lru_cache uses a dict to store the results, all the argumentstaken by the decorated function must be hashable. &nbsp;5.3&nbsp;functools.singledispatch The new functools.singledispatch decorator in Python 3.4 allows each module to contribute to the overall solution, and lets you easily provide a specialized function even for classes that you can&rsquo;t edit. If you decorate a plain function with @singledispatch, it becomes a generic function: a group of functions to perform the same operation in different ways, depending on the type of the first argument. from functools import singledispatch from collections import abc import numbers import html @singledispatch # mark the base function handles the obj type.def htmlize(obj): content = html.escape(repr(obj)) return ‘&lt;pre&gt;{}&lt;/pre&gt;’.format(content) @htmlize.register(str) # @&laquo;base_function&raquo;.register(&laquo;type&raquo;).def _(text): # name of the specialized functions is irrelevant return ‘&lt;p&gt;{0}&lt;/p&gt;’.format(html.escape(text)) @htmlize.register(numbers.Integral)def _(n): return ‘&lt;pre&gt;{0} (0x{0:x})&lt;/pre&gt;’.format(n) @htmlize.register(tuple)@htmlize.register(abc.MutableSequence)def _(seq): inner = ‘&lt;/li&gt;
&lt;li&gt;’.join(htmlize(item) for item in seq) return ‘&lt;ul&gt;
&lt;li&gt;’ + inner + ‘&lt;/li&gt;
&lt;/ul&gt;’ print(htmlize(str)) # &lt;pre&gt;&lt;class ‘str’&gt;&lt;/pre&gt;print(htmlize(‘&lt;hello&gt;’)) # &lt;p&gt;&lt;hello&gt;&lt;/p&gt;print(htmlize(10)) # &lt;pre&gt;10 (0xa)&lt;/pre&gt;print(htmlize([‘alpha’, {3, 2, 1}])) &lt;ul&gt;&lt;li&gt;&lt;p&gt;alpha&lt;/p&gt;&lt;/li&gt;&lt;li&gt;&lt;pre&gt;{1, 2, 3}&lt;/pre&gt;&lt;/li&gt;&lt;/ul&gt;1. Register the specialized functions to handle ABCs (abstract classes)instead of concrete implementations like int and list. (support more)2. A notable quality of the singledispatch mechanism is that you canregister specialized functions anywhere in the system, in any module. &nbsp;6.&nbsp;Stacked Decorators @d1 @d2 def f(): print('f') f = d1(d2(f)) &nbsp;7.&nbsp;Parameterized Decorators Make a decorator factory that takes those arguments and returns a decorator, which is then applied to the function to be decorated. def outter(a=1): def deco(func): def inner(): if a == 1: print(1) else: print(a) return inner return deco @outter()def target1(): pass @outter(9)def target2(): pass target1() # 1target2() # 9 &nbsp;
